!function(){"use strict";document.addEventListener("DOMContentLoaded",function(){const t=new IntersectionObserver(e=>{e.forEach(e=>{e.isIntersecting&&setTimeout(()=>{const n=e.target;n.setAttribute("ot-animate",`${n.getAttribute("ot-animate").replace("view:","")}`),n.classList.add("ot-animated"),t.unobserve(n)},100)})},{rootMargin:"-3px 0px -3px 0px",threshold:.3});document.querySelectorAll('[ot-animate*="view:"]').forEach(e=>{e.getAttribute("ot-animate").startsWith("view:")&&t.observe(e)})})}();
